class Solution:
    def maxCapacity(self, costs, capacity, budget):
        n = len(costs)
        best = 0
        for i in range(n):
            if costs[i] < budget:
                best = max(best, capacity[i])
            for j in range(i + 1, n):
                if costs[i] + costs[j] < budget:
                    best = max(best, capacity[i] + capacity[j])
        return best

