import bisect

class Solution:
    def maxCapacity(self, costs, capacity, budget):
        n = len(costs)
        pairs = sorted(zip(costs, capacity))
        costs_sorted = [c for c, _ in pairs]
        NEG = float('-inf')
        top1_val = [NEG] * (n + 1)
        top1_idx = [-1] * (n + 1)
        top2_val = [NEG] * (n + 1)
        for i in range(1, n + 1):
            c, v = pairs[i - 1]
            if v > top1_val[i - 1]:
                top2_val[i] = top1_val[i - 1]
                top1_val[i] = v
                top1_idx[i] = i - 1
            elif v > top2_val[i - 1]:
                top1_val[i] = top1_val[i - 1]
                top1_idx[i] = top1_idx[i - 1]
                top2_val[i] = v
            else:
                top1_val[i] = top1_val[i - 1]
                top1_idx[i] = top1_idx[i - 1]
                top2_val[i] = top2_val[i - 1]

        best = 0
        for c, v in pairs:
            if c < budget:
                best = max(best, v)

        for j in range(n):
            cj, vj = pairs[j]
            threshold = budget - 1 - cj
            r = bisect.bisect_right(costs_sorted, threshold)
            if r == 0:
                continue
            if top1_idx[r] != j:
                cand = top1_val[r]
            else:
                cand = top2_val[r]
            if cand != NEG:
                best = max(best, vj + cand)
        return best

