var maxCapacity = function(costs, capacity, budget) {
    const n = costs.length;
    const pairs = costs.map((c, i) => [c, capacity[i]]).sort((a, b) => a[0] - b[0]);
    const costsSorted = pairs.map(p => p[0]);
    const NEG = -Infinity;
    const top1Val = new Array(n + 1).fill(NEG);
    const top1Idx = new Array(n + 1).fill(-1);
    const top2Val = new Array(n + 1).fill(NEG);
    for (let i = 1; i <= n; i++) {
        const v = pairs[i - 1][1];
        if (v > top1Val[i - 1]) {
            top2Val[i] = top1Val[i - 1];
            top1Val[i] = v;
            top1Idx[i] = i - 1;
        } else if (v > top2Val[i - 1]) {
            top1Val[i] = top1Val[i - 1];
            top1Idx[i] = top1Idx[i - 1];
            top2Val[i] = v;
        } else {
            top1Val[i] = top1Val[i - 1];
            top1Idx[i] = top1Idx[i - 1];
            top2Val[i] = top2Val[i - 1];
        }
    }

    let best = 0;
    for (const [c, v] of pairs) {
        if (c < budget) best = Math.max(best, v);
    }

    const upperBound = (arr, target) => {
        let lo = 0, hi = arr.length;
        while (lo < hi) {
            const mid = (lo + hi) >> 1;
            if (arr[mid] <= target) lo = mid + 1; else hi = mid;
        }
        return lo;
    };

    for (let j = 0; j < n; j++) {
        const [cj, vj] = pairs[j];
        const threshold = budget - 1 - cj;
        const r = upperBound(costsSorted, threshold);
        if (r === 0) continue;
        const cand = top1Idx[r] !== j ? top1Val[r] : top2Val[r];
        if (cand !== NEG) best = Math.max(best, vj + cand);
    }
    return best;
};
